import zipfile, os, sys
sys.stdout.reconfigure(encoding='utf-8')

dist = 'C:/Users/Lokis/OneDrive/Desktop/T.system/Trade/dist-skills'
apr19 = 'C:/Users/Lokis/OneDrive/Desktop/T.system/.claude/worktrees/brave-davinci-756171/Trade/claude-code-migration/system-backup-2026-04-19/claude-instructions/project-claude/skills'
active = 'C:/Users/Lokis/.claude/skills'

all_skills = set()
for f in os.listdir(dist):
    if f.endswith('.skill'): all_skills.add(f.replace('.skill',''))
for d in os.listdir(apr19): all_skills.add(d)

rows = []
for skill in sorted(all_skills):
    dist_path = f'{dist}/{skill}.skill'
    dist_lines = 0
    if os.path.exists(dist_path):
        try:
            with zipfile.ZipFile(dist_path) as z:
                for n in z.namelist():
                    if n.endswith('SKILL.md'):
                        dist_lines = len(z.read(n).decode('utf-8','ignore').splitlines())
        except: pass
    apr19_path = f'{apr19}/{skill}/SKILL.md'
    apr19_lines = len(open(apr19_path, encoding='utf-8', errors='ignore').readlines()) if os.path.exists(apr19_path) else 0
    active_path = f'{active}/{skill}/SKILL.md'
    active_lines = len(open(active_path, encoding='utf-8', errors='ignore').readlines()) if os.path.exists(active_path) else 0
    best = max(dist_lines, apr19_lines, active_lines)
    src = []
    if dist_lines == best and dist_lines > 0: src.append('dist')
    if apr19_lines == best and apr19_lines > 0: src.append('apr19')
    if active_lines == best and active_lines > 0: src.append('active')
    rows.append((skill, dist_lines, apr19_lines, active_lines, '+'.join(src)))

for r in rows:
    print(f'{r[0]:<33} dist={r[1]:>3} apr19={r[2]:>3} active={r[3]:>3}  best={r[4]}')
